import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Loader2 } from 'lucide-react';
import toast from 'react-hot-toast';

// Re-using your FormField component logic
const FormField = ({ label, value, onChange, placeholder = "", dir = "ltr", disabled = false }: any) => (
  <div className="space-y-1">
    <label className="text-[9px] font-black uppercase text-gray-500 ml-1 tracking-widest">{label}</label>
    <input 
      value={value || ''} 
      onChange={(e) => onChange(e.target.value)} 
      dir={dir} 
      disabled={disabled}
      className={`w-full bg-[#111] border border-white/10 p-4 rounded-2xl text-white outline-none focus:border-primary font-bold transition-all ${disabled ? 'opacity-40 cursor-not-allowed' : ''}`} 
      placeholder={placeholder} 
    />
  </div>
);

export const AdminSeriesForm = () => {
  const { id } = useParams(); // This is the Series_ID from the URL
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(false);

  const [formData, setFormData] = useState({
    Series_ID: '',
    Artist_ID: '',
    Series_Name: '',
    Series_Name_In_Arabic: '',
    Series_Description: '',
    Series_Description_In_Arabic: '',
    Status: 'Complete'
  });

  // --- FETCH DATA FOR MODIFYING ---
  useEffect(() => {
    if (id && id !== 'undefined') {
      setFetching(true);
      AdminService.getSeriesById(id)
        .then((res: any) => {
          // Dive into the backend wrapper: res (Axios) -> data (Backend Body) -> data (Payload)
          const actualData = res.data?.data;
          if (actualData) {
            setFormData(actualData);
          }
        })
        .catch(() => toast.error("Could not retrieve archive record"))
        .finally(() => setFetching(false));
    }
  }, [id]);

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertSeries(formData);
      toast.success(id ? "Record Updated" : "Series Cataloged");
      navigate('/admin/series');
    } catch (err) { 
      toast.error("Operation Failed"); 
    } finally { 
      setLoading(false); 
    }
  };

  if (fetching) return (
    <div className="h-96 flex flex-col items-center justify-center text-primary italic font-black uppercase tracking-widest text-[10px]">
      <Loader2 className="animate-spin mb-4" size={32} />
      Syncing with Archive...
    </div>
  );

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-8 animate-in fade-in duration-700">
      <button onClick={() => navigate('/admin/series')} className="flex items-center gap-2 text-gray-500 font-black text-[10px] uppercase tracking-widest hover:text-white transition-colors">
        <ArrowLeft size={14} /> Back to Series
      </button>

      <form onSubmit={handleManualSubmit} className="bg-[#0f0f0f] border border-white/5 rounded-[2.5rem] p-10 space-y-8 shadow-2xl">
        <h2 className="text-2xl font-black italic uppercase">
          {id ? 'Modify' : 'Manual'} <span className="text-primary">Series Entry</span>
        </h2>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <FormField 
            label="Series ID" 
            value={formData.Series_ID} 
            onChange={(v: string) => setFormData({...formData, Series_ID: v})} 
            disabled={!!id} // LOCKED during modify
            placeholder="e.g., S001" 
          />
          <FormField 
            label="Artist ID" 
            value={formData.Artist_ID} 
            onChange={(v: string) => setFormData({...formData, Artist_ID: v})} 
            placeholder="e.g., AR42" 
          />
          <FormField 
            label="Series Name (EN)" 
            value={formData.Series_Name} 
            onChange={(v: string) => setFormData({...formData, Series_Name: v})} 
          />
          <FormField 
            label="Series Name (AR)" 
            value={formData.Series_Name_In_Arabic} 
            onChange={(v: string) => setFormData({...formData, Series_Name_In_Arabic: v})} 
            dir="rtl" 
          />
        </div>

        <button type="submit" disabled={loading} className="bg-primary text-black px-12 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-white transition-all flex items-center gap-2">
          {loading ? <Loader2 className="animate-spin" size={16} /> : <Save size={18} />}
          {id ? 'Commit Changes' : 'Save Entry'}
        </button>
      </form>
    </div>
  );
};
